803→+ *
804→+ * @param comments - Array of objects with a `body` string field
805→+ * @returns Prior QA findings, or null if no QA phase markers found
806→+ */
807→+export function detectPriorQAFindings(
808→+  comments: { body: string }[],
809→+): PriorQAFindings | null {
810→+  const allMarkers: PhaseMarker[] = [];
811→+
812→+  for (const comment of comments) {
813→+    const markers = parsePhaseMarkers(comment.body);
814→+    for (const marker of markers) {
815→+      if (marker.phase === "qa") {
816→+        allMarkers.push(marker);
817→+      }
818→+    }
819→+  }
820→+
821→+  if (allMarkers.length === 0) {
822→+    return null;
823→+  }
824→+
825→+  // Sort by timestamp descending, return latest
826→+  allMarkers.sort(
827→+    (a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime(),
828→+  );
829→+
830→+  const latest = allMarkers[0];
831→+  return {
832→+    commitSHA: latest.commitSHA ?? null,
833→+    timestamp: latest.timestamp,
834→+    status: latest.status,
835→+  };
836→+}
